UPDATE public.questions SET
  stimulus_text = 'Historians reconstructing trade route 2 emphasize that camel caravans transported not only commodities but also astronomical tables, medical treatises, and navigational techniques across desert corridors long before printed cartography existed. Merchants who survived the crossing depended on star charts copied onto leather scrolls, and successive travelers appended marginal annotations that preserved empirical corrections across generations. A ledger recovered near waypoint 2 records caravan leaders, departure dates, and the scientific manuscripts exchanged at each oasis, suggesting that commerce and scholarship advanced in tandem rather than as separate spheres. When one city-state imposed punitive tariffs, caravans rerouted through secondary wells, and the intellectual networks rerouted with them. Modern scholars therefore treat these desert arteries as early information highways whose reliability depended on reciprocity among communities that rarely shared a written vernacular. The passage underscores how practical navigation imperatives drove the circulation of technical knowledge among traders whose primary motive was profit rather than pedagogy.',
  question_text = 'Which finding from the passage, if true, would most directly strengthen the author''s argument about organizational adaptation during supply-chain disruption?',
  stimulus_type = 'passage',
  options = '[{"id":"A","text":"National chains possess larger advertising budgets than independent retailers, which explains their market share in stable economic periods.","is_correct":false,"explanation":"Advertising budgets do not explain differential adaptation speed during logistics failures described in the passage."},{"id":"B","text":"Independent retailers renegotiated credit with regional suppliers and restocked within days while centralized distribution hubs remained idle for weeks.","is_correct":true,"explanation":"Directly explains the mechanism behind faster adaptation: local reordering cycles that national chains could not match without corporate approval."},{"id":"C","text":"Overseas shipping volumes returned to pre-disruption levels within forty-eight hours across all sectors mentioned in the study.","is_correct":false,"explanation":"Contradicts the passage''s premise that supply chains stalled abruptly and that adaptation timing mattered."},{"id":"D","text":"Desert caravans transported astronomical tables alongside commodities, spreading navigation techniques between oasis settlements.","is_correct":false,"explanation":"This detail belongs to a passage about desert trade routes, not retailer flexibility during modern logistics failures."}]'::jsonb,
  correct_answer = 'B',
  explanation = 'The passage claims independent retailers adapted more nimbly than national chains when supply chains stalled. The passage anchors the correct choice in language such as "Historians reconstructing trade route 2 emphasize that camel caravans transported not only commoditi…", which eliminates options that contradict or overreach that evidence. Choice B is correct because it aligns with the textual logic: . Each incorrect option either contradicts an explicit detail, imports information absent from the stimulus, or answers a different question than the stem asks. On hard Digital SAT items, the best answer synthesizes multiple sentences rather than matching a single keyword in isolation.',
  difficulty = 'hard',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"original":true,"generator":"scholaris_template_v1","explanation_v2":true,"english_content_v2":true,"difficulty_reclassified_at":"2026-06-12T20:24:49.070Z","difficulty_reclassified_to":"medium","english_content_upgraded_at":"2026-06-12T20:01:56.878Z","difficulty_reclassified_from":"hard","difficulty_reclassified_reason":"calibration_shift_down_v1","english_content_upgrade_method":"upgrade-english-content.mjs","hard_content_v2":true,"hard_content_upgraded_at":"2026-06-12T20:29:31.379Z","hard_content_upgrade_method":"generate-hard-english.mjs","prior_difficulty":"medium"}'::jsonb,
